#include <stdio.h>

int countZero(int n) {
    int count = 0;
    for (int i = 0; i <= n; i++) {
        int temp = i;
        while (temp > 0) {
            if (temp % 10 == 0) { // 如果个位数字是0
                count++;
            }
            temp /= 10; // 扔掉个位数字
        }
    }
    return count;
}

int main() {
    int n;
    scanf("%d", &n);

    int result = countZero(n);

    printf("%d\n", result);

    return 0;
}
```

上述代码会从控制台输入一个正整数n，然后使用`countZero`函数计算从0到n的所有整数中0出现的个数，并输出结果。在这个例子中，输入为10，输出为2。

